const STANDARD_DOCS = [
  { key: 'work_auth',    category: 'Customer Documents', label: 'Authorization to Perform Services' },
  { key: 'ins_recovery', category: 'Customer Documents', label: 'Insurance Recovery Agreement' },
  { key: 'cos',          category: 'Customer Documents', label: 'Certificate of Satisfaction' },
];

const JG_SIGNATURE_FONT_TTF = '';
const JG_SIGNER_NAME = 'Josh Greil';
// Registers Alex Brush (SIL OFL 1.1) into a jsPDF doc once, returns true if usable.
// Replaces the old raster signature image with rendered script text so the
// signature is crisp at any scale and never a low-res scribble.
function jgRegisterSigFont(d) {
  try {
    if (d.__alexBrushReady) return true;
    d.addFileToVFS('AlexBrush-Regular.ttf', JG_SIGNATURE_FONT_TTF);
    d.addFont('AlexBrush-Regular.ttf', 'AlexBrush', 'normal');
    d.__alexBrushReady = true;
    return true;
  } catch (e) { console.warn('Alex Brush register failed', e); return false; }
}
// Draws "Josh Greil" as a signature in Alex Brush at (x, baselineY).
// size ~30 reads like the approved sample. Falls back to italic helvetica
// if the font failed to register, so a signature always appears.

async function ensureStandardDocs(projectId) {
  if (!sb || !projectId) return;
  const p = state.activeProject;
  if (!p) return;
  const { data: existing } = await sb.from('rebuild_documents')
    .select('filename').eq('project_id', projectId).eq('category', 'Customer Documents');
  const existingKeys = (existing || []).map(function(d) { return d.filename; });
  // A standard doc "exists" if either the original generated file
  // (work_auth_*, ins_recovery_*, cos_*) OR its signed/renamed variant
  // ("Signed Work Authorization - ...", etc.) is already present.
  // Without the signed-name check, signing renames the file and this
  // check no longer matches, causing a fresh blank duplicate to be
  // regenerated on every load.
  const SIGNED_NAME_BY_KEY = {
    work_auth:    /^signed work authorization\b/i,
    ins_recovery: /^signed insurance recovery agreement\b/i,
    cos:          /^signed certificate of satisfaction\b/i,
  };
  for (var di = 0; di < STANDARD_DOCS.length; di++) {
    var docDef = STANDARD_DOCS[di];
    var signedRe = SIGNED_NAME_BY_KEY[docDef.key];
    if (existingKeys.some(function(f) {
          return f.startsWith(docDef.key + '_') || (signedRe && signedRe.test(f));
        })) continue;
    try {
      var pdfBlob = null;
      if (docDef.key === 'work_auth') pdfBlob = generateWorkAuthPdf(p);
      else if (docDef.key === 'ins_recovery') pdfBlob = generateInsRecoveryPdf(p);
      else if (docDef.key === 'cos') pdfBlob = generateCosPdfBlank(p);
      if (!pdfBlob) continue;
      var filename = docDef.key + '_' + (p.albi_job_number || projectId).replace(/[^a-zA-Z0-9._-]/g, '_') + '.pdf';
      var path = 'projects/' + projectId + '/' + Date.now() + '-' + filename;
      var upResult = await sb.storage.from('rebuild-documents').upload(path, pdfBlob, { contentType: 'application/pdf', upsert: false });
      if (upResult.error) { console.error('Standard doc upload failed:', docDef.key, upResult.error); continue; }
      var urlData = sb.storage.from('rebuild-documents').getPublicUrl(path);
      await sb.from('rebuild_documents').insert({
        project_id: projectId, category: docDef.category, filename: filename,
        file_url: urlData.data.publicUrl, file_size_bytes: pdfBlob.size,
        mime_type: 'application/pdf', uploaded_by_email: 'system@jg-restoration.com',
        push_status: 'skipped', signature_status: 'none',
      });
    } catch (e) { console.error('Standard doc generation failed:', docDef.key, e); }
  }
}

async function loadDocuments() {
  if (!sb) { state.documents = []; return; }
  const { data } = await sb.from('rebuild_documents')
    .select('*').eq('project_id', state.activeProjectId)
    .order('uploaded_at', { ascending: false });
  state.documents = data || [];
  if (state.activeProjectId && window.jspdf) {
    ensureStandardDocs(state.activeProjectId).then(function() {
      sb.from('rebuild_documents').select('*').eq('project_id', state.activeProjectId)
        .order('uploaded_at', { ascending: false })
        .then(function(res) {
          if (res.data && res.data.length !== state.documents.length) {
            state.documents = res.data;
            if (state.tab === 'documents') renderDetail();
          }
        });
    }).catch(function(e) { console.warn('ensureStandardDocs failed:', e); });
  }
}

const PHOTO_STAGES = [
  { id: 'before', label: 'Before', color: '#7884a0' },
  { id: 'during', label: 'During', color: '#f5a623' },
  { id: 'after', label: 'After', color: '#2d9c5f' },
  { id: 'damage', label: 'Damage', color: '#d64545' },
  { id: 'equipment', label: 'Equipment', color: '#0d2d5e' },
  { id: 'issue', label: 'Issue', color: '#e85d04' },
];

function defaultStageForProject() {
  const phases = state.phases || [];
  if (phases.some(p => p.status === 'in_progress')) return 'during';
  if (phases.length && phases.every(p => p.status === 'pending')) return 'before';
  if (phases.some(p => p.status === 'complete') && !phases.some(p => p.status === 'in_progress')) return 'after';
  return 'during';
}

function defaultPhaseIdForProject() {
  const phases = state.phases || [];
  const inProg = phases.find(p => p.status === 'in_progress');
  if (inProg) return inProg.id;
  const lastCompleteIdx = phases.map(p => p.status).lastIndexOf('complete');
  if (lastCompleteIdx >= 0 && lastCompleteIdx + 1 < phases.length) return phases[lastCompleteIdx + 1].id;
  return phases[0]?.id || null;
}

// Pull EXIF DateTimeOriginal + GPS coords from a JPEG file (no external library)
async function extractExifBasics(file) {
  const result = { takenAt: null, lat: null, lng: null, accuracy: null };
  if (!file.type.match(/jpeg|jpg/i)) return result;
  try {
    const buf = await file.slice(0, Math.min(file.size, 256 * 1024)).arrayBuffer();
    const view = new DataView(buf);
    if (view.getUint16(0) !== 0xFFD8) return result;
    let off = 2;
    while (off < view.byteLength) {
      const marker = view.getUint16(off);
      off += 2;
      if (marker === 0xFFE1) {
        const segLen = view.getUint16(off);
        if (view.getUint32(off + 2) !== 0x45786966) { off += segLen; continue; }
        const tiffStart = off + 8;
        const little = view.getUint16(tiffStart) === 0x4949;
        const get16 = (o) => little ? view.getUint16(o, true) : view.getUint16(o);
        const get32 = (o) => little ? view.getUint32(o, true) : view.getUint32(o);
        const ifd0Off = tiffStart + get32(tiffStart + 4);
        const numTags = get16(ifd0Off);
        let exifIfdOff = null, gpsIfdOff = null;
        for (let i = 0; i < numTags; i++) {
          const tagOff = ifd0Off + 2 + i * 12;
          const tag = get16(tagOff);
          if (tag === 0x8769) exifIfdOff = tiffStart + get32(tagOff + 8);
          if (tag === 0x8825) gpsIfdOff = tiffStart + get32(tagOff + 8);
        }
        if (exifIfdOff) {
          const en = get16(exifIfdOff);
          for (let i = 0; i < en; i++) {
            const tagOff = exifIfdOff + 2 + i * 12;
            const tag = get16(tagOff);
            if (tag === 0x9003) {
              const len = get32(tagOff + 4);
              const valOff = tiffStart + get32(tagOff + 8);
              let s = '';
              for (let j = 0; j < Math.min(len, 19); j++) s += String.fromCharCode(view.getUint8(valOff + j));
              const m = s.match(/(\d{4}):(\d{2}):(\d{2}) (\d{2}):(\d{2}):(\d{2})/);
              if (m) result.takenAt = new Date(`${m[1]}-${m[2]}-${m[3]}T${m[4]}:${m[5]}:${m[6]}`).toISOString();
            }
          }
        }
        if (gpsIfdOff) {
          const gn = get16(gpsIfdOff);
          let latRef = 'N', lngRef = 'E', latRat = null, lngRat = null;
          const readRational3 = (o) => {
            const valOff = tiffStart + get32(o + 8);
            const r = [];
            for (let k = 0; k < 3; k++) {
              const num = get32(valOff + k * 8);
              const den = get32(valOff + k * 8 + 4);
              r.push(den ? num / den : 0);
            }
            return r;
          };
          for (let i = 0; i < gn; i++) {
            const tagOff = gpsIfdOff + 2 + i * 12;
            const tag = get16(tagOff);
            if (tag === 1) latRef = String.fromCharCode(view.getUint8(tagOff + 8));
            if (tag === 2) latRat = readRational3(tagOff);
            if (tag === 3) lngRef = String.fromCharCode(view.getUint8(tagOff + 8));
            if (tag === 4) lngRat = readRational3(tagOff);
          }
          if (latRat && lngRat) {
            const dms = ([d, m, s], ref) => {
              const v = d + m/60 + s/3600;
              return (ref === 'S' || ref === 'W') ? -v : v;
            };
            result.lat = dms(latRat, latRef);
            result.lng = dms(lngRat, lngRef);
          }
        }
        break;
      } else if ((marker & 0xFF00) !== 0xFF00) break;
      else off += view.getUint16(off);
    }
  } catch (e) { console.warn('EXIF parse failed', e); }
  return result;
}

function getCurrentLocation() {
  return new Promise((resolve) => {
    if (!navigator.geolocation) return resolve(null);
    navigator.geolocation.getCurrentPosition(
      pos => resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude, accuracy: pos.coords.accuracy }),
      () => resolve(null),
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 60000 }
    );
  });
}

function openPhotoEditor(id) {
  const ph = state.documents.find(x => x.id === id);
  if (!ph) return;

  let modal = document.getElementById('modalPhotoEdit');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'modalPhotoEdit';
    modal.className = 'modal-back';
    modal.innerHTML = `
      <div class="modal" style="max-width:520px;">
        <h3>Edit Photo <button class="close" data-close>×</button></h3>
        <div class="modal-body" id="pebBody"></div>
        <div class="modal-foot">
          <div style="flex:1"></div>
          <button class="btn" data-close>Cancel</button>
          <button class="btn primary" id="peb_save">Save</button>
        </div>
      </div>
    `;
    document.body.appendChild(modal);
    modal.querySelectorAll('[data-close]').forEach(el => el.addEventListener('click', () => modal.classList.remove('on')));
  }

  const phases = state.phases || [];
  modal.querySelector('#pebBody').innerHTML = `
    <div style="text-align:center;margin-bottom:14px;">
      <img src="${ph.file_url}" style="max-width:100%;max-height:200px;border-radius:6px;border:1px solid var(--line);">
    </div>
    <label>Stage</label>
    <select id="peb_stage">
      <option value="">— No stage —</option>
      ${PHOTO_STAGES.map(s => `<option value="${s.id}" ${s.id===ph.stage?'selected':''}>${s.label}</option>`).join('')}
    </select>
    <label>Phase</label>
    <select id="peb_phase">
      <option value="">— No phase —</option>
      ${phases.map(p => `<option value="${p.id}" ${p.id===ph.phase_id?'selected':''}>${String(p.sequence).padStart(2,'0')} · ${p.phase_name}</option>`).join('')}
    </select>
    <label>Caption</label>
    <textarea id="peb_caption" rows="3">${ph.caption || ''}</textarea>
  `;

  const saveBtn = modal.querySelector('#peb_save');
  const newBtn = saveBtn.cloneNode(true);
  saveBtn.parentNode.replaceChild(newBtn, saveBtn);
  newBtn.addEventListener('click', async () => {
    const phaseId = modal.querySelector('#peb_phase').value || null;
    const phaseName = phaseId ? phases.find(p => p.id === phaseId)?.phase_name : null;
    await sb.from('rebuild_documents').update({
      stage: modal.querySelector('#peb_stage').value || null,
      phase_id: phaseId,
      phase_name: phaseName,
      caption: modal.querySelector('#peb_caption').value.trim() || null,
    }).eq('id', id);
    modal.classList.remove('on');
    toast('Updated');
    await loadDocuments();
    renderDetail();
  });
  modal.classList.add('on');
}

