// ─────────── PDF Project Report Builder ───────────

const REPORT_SECTIONS = [
  { id: 'cover', label: 'Cover Sheet', alwaysOn: true },
  { id: 'summary', label: 'Project Summary' },
  { id: 'phases', label: 'Phase Schedule', defaultOff: true },
  { id: 'selections', label: 'Material Selections' },
  { id: 'photos', label: 'Photos (by phase)' },
  { id: 'documents', label: 'Documents (by category)', defaultOff: true },
  { id: 'audit', label: 'Audit Trail', defaultOff: true },
];

function openReportBuilder() {
  if (!state.activeProjectId) return;
  const p = state.activeProject;

  // Group documents by category for the per-file picker
  const docsByCategory = {};
  for (const cat of DOC_CATEGORIES) docsByCategory[cat] = [];
  for (const d of (state.documents || [])) {
    if (docsByCategory[d.category]) docsByCategory[d.category].push(d);
  }

  let modal = document.getElementById('modalBuildReport');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'modalBuildReport';
    modal.className = 'modal-back';
    modal.innerHTML = `
      <div class="modal" style="max-width:760px;max-height:90vh;display:flex;flex-direction:column;">
        <h3>Build PDF Report <button class="close" data-close>×</button></h3>
        <div class="modal-body" id="rbBody" style="flex:1;overflow-y:auto;"></div>
        <div class="modal-foot">
          <div style="flex:1;font-size:11px;color:var(--muted);">Drag handles ⋮⋮ to reorder</div>
          <button class="btn" data-close>Cancel</button>
          <button class="btn primary" id="rb_generate">Generate PDF</button>
        </div>
      </div>
    `;
    document.body.appendChild(modal);
    modal.querySelectorAll('[data-close]').forEach(el =>
      el.addEventListener('click', () => modal.classList.remove('on'))
    );
  }

  // Build the section list with checkboxes + drag handles
  const sectionsHtml = REPORT_SECTIONS.map(s => {
    const checkAttrs = s.alwaysOn ? 'checked disabled' : (s.defaultOff ? '' : 'checked');
    return `
      <div class="rb-row" data-section-id="${s.id}" draggable="${!s.alwaysOn}">
        <span class="rb-handle" title="Drag to reorder">⋮⋮</span>
        <input type="checkbox" data-section="${s.id}" ${checkAttrs}>
        <span class="rb-row-label">${s.label}</span>
        ${s.alwaysOn ? '<span class="rb-tag">Always</span>' : ''}
      </div>`;
  }).join('');

  // Per-file picker — clean grid layout matching sections, with thumbnails
  const isImageFile = fn => /\.(jpe?g|png|gif|webp|heic)$/i.test(fn || '');
  const isPdfFile = fn => /\.pdf$/i.test(fn || '');
  const filePickerHtml = DOC_CATEGORIES.filter(cat => docsByCategory[cat]?.length).map(cat => `
    <div class="rb-cat-header">
      <input type="checkbox" class="rb-cat-toggle" data-cat="${cat}" checked>
      <span class="rb-cat-label">${cat}</span>
      <span class="rb-cat-count">${docsByCategory[cat].length}</span>
    </div>
    ${docsByCategory[cat].map(d => {
      const thumb = isImageFile(d.filename)
        ? `<img src="${d.file_url}" class="rb-doc-thumb" loading="lazy" alt="" onerror="this.outerHTML='<div class=&quot;rb-doc-thumb rb-doc-icon&quot;>📄</div>'">`
        : isPdfFile(d.filename)
          ? `<div class="rb-doc-thumb rb-doc-pdf-thumb" data-pdf-thumb="${d.file_url}" data-doc-id="${d.id}"><span class="rb-doc-pdf-fallback">📕</span></div>`
          : `<div class="rb-doc-thumb rb-doc-icon">📄</div>`;
      return `
        <div class="rb-row rb-doc-row">
          <span class="rb-handle"></span>
          <input type="checkbox" class="rb-doc" data-doc-id="${d.id}" data-cat="${cat}" checked>
          ${thumb}
          <span class="rb-row-label rb-doc-name">${cleanFilename(d.filename)}</span>
        </div>`;
    }).join('')}
  `).join('');

  // Cover photo picker - all images from Photos folder
  const coverPhotos = (state.documents || []).filter(d =>
    d.category === 'Photos' && /\.(jpe?g|png|gif|webp|heic)$/i.test(d.filename)
  );
  const coverPhotoPickerHtml = coverPhotos.length
    ? coverPhotos.map((d, idx) => `
        <label class="rb-cover-photo ${idx === 0 ? 'selected' : ''}" data-photo-url="${d.file_url}">
          <input type="radio" name="rb_cover_photo" value="${d.file_url}" ${idx === 0 ? 'checked' : ''}>
          <img src="${d.file_url}" loading="lazy" alt="">
        </label>`).join('')
    + `<label class="rb-cover-photo" data-photo-url="">
         <input type="radio" name="rb_cover_photo" value="">
         <div class="rb-cover-none">No photo</div>
       </label>`
    : '<div style="padding:14px;font-size:12px;color:var(--muted);font-style:italic;">No photos uploaded yet — cover will use a striped placeholder.</div>';

  modal.querySelector('#rbBody').innerHTML = `
    <div style="background:var(--bg);padding:12px 14px;border-radius:6px;margin-bottom:14px;">
      <div style="font-size:11px;font-weight:700;text-transform:uppercase;color:var(--muted);letter-spacing:.4px;margin-bottom:4px;">Project</div>
      <div style="font-size:14px;font-weight:700;color:var(--navy);">${p.albi_job_number || ''}</div>
      <div style="font-size:12px;color:var(--text);">${p.customer_name || ''} · ${p.property_address || ''}</div>
    </div>

    <label style="display:block;margin-bottom:6px;font-weight:700;font-size:13px;">Report Title</label>
    <input type="text" id="rb_title" value="Project Report" style="margin-bottom:14px;">

    <label style="display:block;margin-bottom:6px;font-weight:700;font-size:13px;">Cover Photo <span style="font-size:11px;color:var(--muted);font-weight:400;">(pick one to feature on the cover)</span></label>
    <div id="rb_cover_photos" style="border:1px solid var(--line);border-radius:6px;padding:8px;background:var(--card);margin-bottom:14px;display:flex;gap:8px;overflow-x:auto;">
      ${coverPhotoPickerHtml}
    </div>

    <label style="display:block;margin-bottom:6px;font-weight:700;font-size:13px;">Sections to Include <span style="font-size:11px;color:var(--muted);font-weight:400;">(drag to reorder)</span></label>
    <div id="rb_sections" style="border:1px solid var(--line);border-radius:6px;background:var(--card);margin-bottom:14px;">
      ${sectionsHtml}
    </div>

    <label style="display:block;margin-bottom:6px;font-weight:700;font-size:13px;">Documents to Attach <span style="font-size:11px;color:var(--muted);font-weight:400;">(uncheck files you want to exclude)</span></label>
    <div id="rb_docs_container" style="border:1px solid var(--line);border-radius:6px;background:var(--card);max-height:340px;overflow-y:auto;">
      ${filePickerHtml || '<div style="padding:16px;font-size:12px;color:var(--muted);font-style:italic;text-align:center;">No documents uploaded yet.</div>'}
    </div>
  `;

  // Cover photo selection — visual highlight
  modal.querySelectorAll('.rb-cover-photo').forEach(el => {
    el.addEventListener('click', () => {
      modal.querySelectorAll('.rb-cover-photo').forEach(p => p.classList.remove('selected'));
      el.classList.add('selected');
    });
  });

  // Drag-drop reorder for sections
  let dragSrc = null;
  modal.querySelectorAll('.rb-row[draggable="true"]').forEach(el => {
    el.addEventListener('dragstart', e => { dragSrc = el; el.style.opacity = '0.4'; });
    el.addEventListener('dragend', () => { el.style.opacity = ''; dragSrc = null; });
    el.addEventListener('dragover', e => { e.preventDefault(); });
    el.addEventListener('drop', e => {
      e.preventDefault();
      if (!dragSrc || dragSrc === el) return;
      const parent = el.parentNode;
      const items = [...parent.children];
      const srcIdx = items.indexOf(dragSrc);
      const dstIdx = items.indexOf(el);
      parent.insertBefore(dragSrc, srcIdx < dstIdx ? el.nextSibling : el);
    });
  });

  // Category checkbox toggles all child docs
  modal.querySelectorAll('.rb-cat-toggle').forEach(cb => {
    cb.addEventListener('change', () => {
      modal.querySelectorAll(`.rb-doc[data-cat="${cb.dataset.cat}"]`).forEach(d => {
        d.checked = cb.checked;
      });
    });
  });

  // Generate handler
  const genBtn = modal.querySelector('#rb_generate');
  const newGen = genBtn.cloneNode(true);
  genBtn.parentNode.replaceChild(newGen, genBtn);
  newGen.addEventListener('click', async () => {
    const orderedSections = [...modal.querySelectorAll('#rb_sections .rb-row')]
      .filter(el => {
        const cb = modal.querySelector(`input[data-section="${el.dataset.sectionId}"]`);
        return cb && cb.checked;
      })
      .map(el => el.dataset.sectionId);

    const selectedDocIds = [...modal.querySelectorAll('.rb-doc:checked')].map(cb => cb.dataset.docId);
    const reportTitle = modal.querySelector('#rb_title').value.trim() || 'Project Report';
    const coverPhotoUrl = modal.querySelector('input[name="rb_cover_photo"]:checked')?.value || '';

    // Close modal immediately so user can keep working
    modal.classList.remove('on');

    // Show floating progress card
    showReportProgress(reportTitle);

    try {
      const reportDoc = await generateProjectReportPdf({
        sections: orderedSections,
        docIds: selectedDocIds,
        reportTitle,
        coverPhotoUrl,
      });
      hideReportProgress();
      showReportComplete(reportTitle, reportDoc);
    } catch (e) {
      console.error(e);
      hideReportProgress();
      showReportError(e.message || 'Failed');
    }
  });

  modal.classList.add('on');
  // Render PDF first-page thumbnails for files in the picker
  modal.querySelectorAll('[data-pdf-thumb]').forEach(el => renderPdfThumbnail(el));
}

async function deleteDocument(docId) {
  const d = state.documents.find(x => x.id === docId);
  if (!d) return;
  if (!confirm(`Delete "${d.filename}"?`)) return;
  // Try to remove from storage too (best-effort)
  try {
    const path = d.file_url.split('/rebuild-documents/')[1];
    if (path) await sb.storage.from('rebuild-documents').remove([path]);
  } catch (e) { console.warn('Storage cleanup failed:', e); }
  await sb.from('rebuild_documents').delete().eq('id', docId);
  toast('Deleted');
  await loadDocuments();
  renderDetail();
}


